def transform(table):
    if not table:
        return []
    header = table[0]
    data = table[1:]
    if not data:
        return []

    item_to_dates = defaultdict(list)
    item_to_values = defaultdict(list)

    for row in data:
        item = row[0]
        for i, date in enumerate(header[1:]):
            value = row[i + 1]
            if value:
                item_to_dates[item].append(date)
                item_to_values[item].append(value)

    result = []
    for item in item_to_dates:
        dates = sorted(item_to_dates[item])
        values = item_to_values[item]
        for i, date in enumerate(dates):
            result.append([item, date, values[i] if i < len(values) else ""])

    return result

